}

function BreadcrumbLink({
  asChild,
  className,
  ...props
}: React.ComponentProps<"a"> & {
  asChild?: boolean
}) {
  const Comp = asChild ? Slot.Root : "a"

  return (
    <Comp
      data-slot="breadcrumb-link"
      className={cn("transition-colors hover:text-foreground", className)}
      {...props}
    />
  )
}

function BreadcrumbPage({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="breadcrumb-page"
      role="link"
      aria-disabled="true"
      aria-current="page"
      className={cn("font-normal text-foreground", className)}
      {...props}
    />
  )
}

function FieldError({
  className,
  children,
  errors,
  ...props
}: React.ComponentProps<"div"> & {
  errors?: Array<{ message?: string } | undefined>
}) {
  const content = useMemo(() => {
    if (children) {
      return children
    }

    if (!errors?.length) {
      return null
    }

    const uniqueErrors = [
      ...new Map(errors.map((error) => [error?.message, error])).values(),
    ]

    if (uniqueErrors?.length == 1) {
      return uniqueErrors[0]?.message
    }

    return (
      <ul className="ml-4 flex list-disc flex-col gap-1">
        {uniqueErrors.map(
          (error, index) =>
            error?.message && <li key={index}>{error.message}</li>
        )}
      </ul>
    )
  }, [children, errors])

  if (!content) {
    return null
  }

  return (
    <div
      role="alert"
      data-slot="field-error"
      className={cn("text-xs font-normal text-destructive", className)}
      {...props}
    >
      {content}
    </div>
  )
}

export default function PostMinimal({ content, next, prev, children }: LayoutProps) {
  const { slug, title, images } = content
  return (
    <SectionContainer>
      <article>
        <header className="space-y-1 border-b border-gray-200 pb-10 text-center dark:border-gray-700">
          <PageTitle>{title}</PageTitle>
        </header>
        <div className="prose dark:prose-invert max-w-none py-4">
          {children}
        </div>
        <footer>
          <div className="flex flex-col text-sm font-medium sm:flex-row sm:justify-between">
            {prev && prev.path && (
              <Link href={`/${prev.path}`}
                className="text-primary-500 hover:text-primary-600 dark:hover:text-primary-400 pt-4 xl:pt-8">
                &larr; {prev.title}
              </Link>
            )}
            {next && next.path && (
              <Link href={`/${next.path}`}
                className="text-primary-500 hover:text-primary-600 dark:hover:text-primary-400 pt-4 xl:pt-8">
                {next.title} &rarr;
              </Link>
            )}
          </div>
        </footer>
      </article>
    </SectionContainer>
  )
}

